from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """Generate a natural‑language description from a list of triples.

    The function builds a fluent sentence using simple templates for
    common predicates (e.g., *builder* → “was built by”).  Unknown
    predicates are rendered in a readable “subject predicate object”
    form.  Multiple clauses are combined with commas and a final “and”
    for a natural‑sounding complex sentence.
    """
    if not triples:
        return ""

    def format_clause(t: Triple) -> str:
        s, p, o = t.subject, t.predicate, t.object
        # Specific predicate templates
        if p == "alternativeName":
            return f"{s} is also known as {o}"
        if p == "builder":
            return f"{s} was built by {o}"
        if p in {
            "completionDate", "launchDate", "shipLaunch", "shipOrdered",
            "shipLaidDown", "maidenVoyage", "christeningDate",
            "activeYearsStartDate", "buildDate", "shipInService"
        }:
            return f"{s} was completed on {o}"
        if p == "length":
            return f"{s} has a length of {o}"
        if p == "width":
            return f"{s} is {o} wide"
        if p == "height":
            return f"{s} is {o} tall"
        if p == "shipPower":
            return f"{s} is powered by {o}"
        if p == "topSpeed":
            return f"{s} can reach a top speed of {o}"
        if p == "engine":
            return f"{s} is equipped with {o}"
        if p == "manufacturer":
            return f"{s} was manufactured by {o}"
        if p == "owner":
            return f"{s} is owned by {o}"
        if p == "location":
            return f"{s} is located in {o}"
        if p == "status":
            return f"{s} is currently {o}"
        if p == "class":
            return f"{s} belongs to the class {o}"
        # Default fallback
        pred = p.replace("_", " ")
        return f"{s} {pred} {o}"

    clauses = [format_clause(t) for t in triples]

    if len(clauses) == 1:
        sentence = clauses[0]
    else:
        sentence = ", ".join(clauses[:-1]) + ", and " + clauses[-1]

    return sentence.rstrip() + "."

